import { Resend } from "resend";
import { env } from "@/env";

/**
 * Initialize Resend with API key if available, otherwise return null
 * This allows the application to build even if RESEND_API_KEY is not set
 * Falls back to RESEND_API_KEY for backward compatibility
 */
export const resend = env.RESEND_API_KEY ? new Resend(env.RESEND_API_KEY) : null;

import "server-only";
import { adminConfig } from "@/config/admin-config";
import { env } from "@/env";

interface MailtoOptions {
  to?: string | string[];
  subject?: string;
  body?: string;
  cc?: string | string[];
  bcc?: string | string[];
}

/**
 * Generate a mailto link with proper URL encoding
 * @param options - Email options for the mailto link
 * @returns Formatted mailto URL
 */
export function generateMailtoLink(options: MailtoOptions): string {
  const params = new URLSearchParams();

  // Handle recipients (to)
  if (options.to) {
    const recipients = Array.isArray(options.to) ? options.to.join(",") : options.to;
    params.set("to", recipients);
  }

  // Handle subject
  if (options.subject) {
    params.set("subject", options.subject);
  }

  // Handle body
  if (options.body) {
    params.set("body", options.body);
  }

  // Handle CC
  if (options.cc) {
    const ccRecipients = Array.isArray(options.cc) ? options.cc.join(",") : options.cc;
    params.set("cc", ccRecipients);
  }

  // Handle BCC
  if (options.bcc) {
    const bccRecipients = Array.isArray(options.bcc) ? options.bcc.join(",") : options.bcc;
    params.set("bcc", bccRecipients);
  }

  // Build the mailto URL
  const baseMailto = "mailto:";
  const queryString = params.toString();

  return queryString ? `${baseMailto}?${queryString}` : baseMailto;
}

/**
 * Generate a feedback mailto link using admin emails
 * @param content - The feedback content
 * @param source - Source of the feedback (dialog, popover, etc.)
 * @returns Formatted mailto URL for feedback
 */
export function generateFeedbackMailto(content: string, source: string): string {
  const adminEmails = adminConfig.emails;
  const subject = `Feedback from ${source} - Shipkit`;

  return generateMailtoLink({
    to: adminEmails[0], // Use first admin email as primary recipient
    cc: adminEmails.length > 1 ? adminEmails.slice(1) : undefined,
    subject,
    body: content,
  });
}

/**
 * Check if email service is available (Resend configured)
 * This function is for server-side use only
 * @returns Boolean indicating if email service is available
 */
export function isEmailServiceAvailable(): boolean {
  return !!env.RESEND_API_KEY;
}

import { RESEND_FROM_EMAIL } from "@/config/constants";
import { siteConfig } from "@/config/site-config";
import { resend } from "@/lib/resend";

export const sendFeedbackEmail = async (content: string): Promise<void> => {
  try {
    if (!resend) {
      console.warn("Resend client not initialized - RESEND_API_KEY not set");
      return;
    }

    const result = await resend.emails.send({
      from: `🍱 ${siteConfig.title} <${RESEND_FROM_EMAIL}>`,
      to: [siteConfig.creator.email],
      subject: "New Feedback Received",
      html: `<p>${content}</p>`,
    });

    console.debug("Feedback sent successfully", result);
  } catch (error) {
    console.error("Error sending feedback:", error);
    throw new Error("Failed to send feedback email");
  }
};

"use server";

import { env } from "@/env";
import { resend } from "@/lib/resend";
import { sendFeedbackEmail } from "@/server/services/resend-service";

export const sendFeedback = async (content: string): Promise<void> => {
  try {
    await sendFeedbackEmail(content);
  } catch (error) {
    console.error("Error in sendFeedback action:", error);
    throw error;
  }
};

/**
 * Adds a contact to the Resend audience.
 * @param email - The email of the contact to add.
 * @returns A promise that resolves when the contact is added.
 */
export const addAudienceUser = async (email: string) => {
  try {
    if (!env.RESEND_AUDIENCE_ID) {
      throw new Error("Missing Resend API key or audience ID");
    }

    if (!resend) {
      throw new Error("Resend client not initialized");
    }

    const result = await resend.contacts.create({
      email,
      audienceId: env.RESEND_AUDIENCE_ID,
    });

    return { success: true };
  } catch (error: unknown) {
    if (error instanceof Error) {
      console.error("Error adding contact:", error.message);
      return { success: false, error: error.message };
    }
    console.error("Error adding contact:", error);
    return { success: false, error: "An unknown error occurred" };
  }
};

"use server";

import { env } from "@/env";
import { resend } from "@/lib/resend";

/**
 * Adds a contact to the Resend audience.
 * @param email - The email of the contact to add.
 * @returns A promise that resolves when the contact is added.
 */
export const addContactToAudience = async (email: string) => {
  try {
    if (!env.RESEND_API_KEY || !env.RESEND_AUDIENCE_ID) {
      throw new Error("Missing Resend API key or audience ID");
    }

    const result = await resend?.contacts.create({
      email,
      audienceId: env.RESEND_AUDIENCE_ID,
    });

    console.debug("result", result);
    return { success: true };
  } catch (error: unknown) {
    if (error instanceof Error) {
      console.error("Error adding contact:", error.message);
      return { success: false, error: error.message };
    }

    console.error("Error adding contact:", error);
    return { success: false, error: "An unknown error occurred" };
  }
};

"use client";

import { ArrowRightIcon } from "@radix-ui/react-icons";
import type React from "react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";
import { addAudienceUser } from "@/server/actions/resend-actions";

export const SubscribeForm: React.FC = () => {
  const [email, setEmail] = useState("");
  const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
  const { toast } = useToast();

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    setStatus("loading");

    try {
      const result = await addAudienceUser(email);

      if (result.success) {
        setStatus("success");
        setEmail("");
        toast({
          title: "Subscribed!",
          description: "You've been successfully subscribed to our newsletter.",
        });
      } else {
        console.error("Error adding contact:", result.error);
        setStatus("error");
        toast({
          title: "Subscription failed",
          description: result.error || "Failed to subscribe. Please try again.",
          variant: "destructive",
        });
      }
    } catch (error) {
      console.error("Error submitting form:", error);
      setStatus("error");
      toast({
        title: "Subscription failed",
        description: "An unexpected error occurred. Please try again.",
        variant: "destructive",
      });
    } finally {
      // Reset status after a delay
      setTimeout(() => {
        setStatus("idle");
      }, 3000);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-md">
      <p className="">Sign up to be notified of new features and updates.</p>
      <div className="relative flex items-center justify-center">
        <Input
          type="email"
          placeholder="me@shipkit.io"
          className=""
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />
        <Button
          type="submit"
          variant="outline"
          disabled={status === "loading"}
          className={cn(
            "absolute bottom-0 right-0 top-0 z-10 rounded-s-none border-0 border-s-0 bg-transparent text-primary"
          )}
        >
          {status === "loading" ? (
            "Subscribing..."
          ) : (
            <>
              Subscribe
              <ArrowRightIcon className="ml-2" />
            </>
          )}
        </Button>
      </div>
    </form>
  );
};
